#!/usr/bin/env bash
set -euo pipefail

echo "================================================================"
echo "  Simulador de Premiação - Instalador ADS Software (v2)"
echo "  Instala duas pastas separadas: consultor e supervisor"
echo "================================================================"

# 1) Detectar gerenciador de pacotes
if command -v apt >/dev/null 2>&1; then
  export DEBIAN_FRONTEND=noninteractive
  echo "==> Usando APT (Debian/Ubuntu)"
  apt update -qq
  apt install -y -qq apache2 unzip curl >/dev/null
  WEBSERVER="apache2"
elif command -v dnf >/dev/null 2>&1; then
  echo "==> Usando DNF (Rocky/Alma/Fedora)"
  dnf install -y -q httpd unzip curl >/dev/null
  WEBSERVER="httpd"
elif command -v yum >/dev/null 2>&1; then
  echo "==> Usando YUM (CentOS/RHEL)"
  yum install -y -q httpd unzip curl >/dev/null
  WEBSERVER="httpd"
else
  echo "ERRO: gerenciador de pacotes não detectado."
  exit 1
fi

# 2) Detectar pasta web e usuário
if   [ -d /var/www/html ]; then BASE="/var/www/html"
elif [ -d /var/www ];      then BASE="/var/www"
else BASE="/srv"; mkdir -p "$BASE"; fi

CONS_DIR="$BASE/consultor"
SUP_DIR="$BASE/supervisor"

if   id www-data >/dev/null 2>&1; then WEBUSER="www-data:www-data"
elif id apache  >/dev/null 2>&1; then WEBUSER="apache:apache"
elif id nginx   >/dev/null 2>&1; then WEBUSER="nginx:nginx"
else WEBUSER="root:root"; fi

mkdir -p "$CONS_DIR" "$SUP_DIR"
TMPZIP=$(mktemp --suffix=.zip)

echo "==> Decodificando arquivos do simulador..."
base64 -d > "$TMPZIP" << 'BASE64_PAYLOAD'

BASE64_PAYLOAD

echo "==> Extraindo para a pasta do consultor..."
unzip -o -q "$TMPZIP" -d "$CONS_DIR"
# Em /consultor: o index.html é o consultor-premiacao.html
cp "$CONS_DIR/consultor-premiacao.html" "$CONS_DIR/index.html"

echo "==> Extraindo para a pasta do supervisor..."
unzip -o -q "$TMPZIP" -d "$SUP_DIR"
# Em /supervisor: o index.html é o supervisor-premiacao.html
cp "$SUP_DIR/supervisor-premiacao.html" "$SUP_DIR/index.html"

rm -f "$TMPZIP"

# 3) Permissões
chown -R "$WEBUSER" "$CONS_DIR" "$SUP_DIR"
chmod -R 755 "$CONS_DIR" "$SUP_DIR"

# 4) Templates de VirtualHost (criados, NÃO ativados — pra você ativar quando o DNS apontar)
TEMPLATE_DIR="$BASE/_simulador_vhost_templates"
mkdir -p "$TEMPLATE_DIR"

cat > "$TEMPLATE_DIR/consultor.conf.template" << EOF
# Apontar consultor.SEUDOMINIO.com.br para este servidor.
# Mover para /etc/apache2/sites-available/ (Ubuntu/Debian) ou /etc/httpd/conf.d/ (CentOS/Rocky)
# E rodar: a2ensite consultor && systemctl reload apache2
<VirtualHost *:80>
    ServerName consultor.SEUDOMINIO.com.br
    DocumentRoot $CONS_DIR
    DirectoryIndex index.html
    <Directory $CONS_DIR>
        Require all granted
        AllowOverride All
    </Directory>
    ErrorLog \${APACHE_LOG_DIR}/consultor-error.log
    CustomLog \${APACHE_LOG_DIR}/consultor-access.log combined
</VirtualHost>
EOF

cat > "$TEMPLATE_DIR/supervisor.conf.template" << EOF
# Apontar supervisor.SEUDOMINIO.com.br para este servidor.
<VirtualHost *:80>
    ServerName supervisor.SEUDOMINIO.com.br
    DocumentRoot $SUP_DIR
    DirectoryIndex index.html
    <Directory $SUP_DIR>
        Require all granted
        AllowOverride All
    </Directory>
    ErrorLog \${APACHE_LOG_DIR}/supervisor-error.log
    CustomLog \${APACHE_LOG_DIR}/supervisor-access.log combined
</VirtualHost>
EOF

# 5) Garantir Apache rodando
if systemctl list-units --type=service --all 2>/dev/null | grep -q apache2; then
  systemctl enable --now apache2 >/dev/null 2>&1 || true
elif systemctl list-units --type=service --all 2>/dev/null | grep -q httpd; then
  systemctl enable --now httpd >/dev/null 2>&1 || true
fi

# 6) Firewall
command -v ufw >/dev/null 2>&1 && ufw allow 80/tcp >/dev/null 2>&1 || true
command -v firewall-cmd >/dev/null 2>&1 && {
  firewall-cmd --permanent --add-service=http >/dev/null 2>&1 || true
  firewall-cmd --reload >/dev/null 2>&1 || true
}

# 7) IP público
IP=$(curl -s --max-time 5 https://api.ipify.org 2>/dev/null || hostname -I | awk '{print $1}')

cat << FIM

================================================================
  INSTALADO COM SUCESSO
================================================================

  IP da VPS: $IP

  PASTAS NO SERVIDOR:
    Consultor:  $CONS_DIR
    Supervisor: $SUP_DIR

  ACESSO IMEDIATO (pelo IP, sem subdomínio):
    Consultor:  http://$IP/consultor/
    Supervisor: http://$IP/supervisor/
    Testes:     http://$IP/consultor/testes.html

  QUANDO VOCÊ APONTAR OS SUBDOMÍNIOS:
    1) No painel do registrador (Registro.br, Hostinger, etc.):
       - Crie 2 registros tipo A apontando para $IP
       - Ex: consultor.empresa.com.br -> $IP
            supervisor.empresa.com.br -> $IP

    2) Na VPS, ative os VirtualHosts:
       cp $TEMPLATE_DIR/consultor.conf.template /etc/apache2/sites-available/consultor.conf
       cp $TEMPLATE_DIR/supervisor.conf.template /etc/apache2/sites-available/supervisor.conf
       (substituir SEUDOMINIO.com.br nos arquivos pelo seu domínio real)
       a2ensite consultor supervisor
       systemctl reload apache2

    3) HTTPS grátis (Let's Encrypt):
       apt install -y certbot python3-certbot-apache
       certbot --apache -d consultor.empresa.com.br -d supervisor.empresa.com.br

================================================================
FIM
